#include <stdio.h>
#include <stdlib.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int R,C,X; scanf("%d %d %d", &R, &C, &X);
        long long *A = (long long*)malloc(sizeof(long long)*R*C);
        for(int i=0;i<R*C;i++) scanf("%lld", &A[i]);
        long long sumDiff = 0;
        for(int i=0;i<R*C;i++){
            long long b; scanf("%lld", &b);
            sumDiff += b - A[i];
        }
        free(A);
        if(((sumDiff % X) + X) % X == 0) printf("Yes\n");
        else printf("No\n");
    }
    return 0;
}

